patch:
diff --git a/llvm/lib/Transforms/Scalar/ConstraintElimination.cpp b/llvm/lib/Transforms/Scalar/ConstraintElimination.cpp
index 456f5086309c..325a20633284 100644
--- a/llvm/lib/Transforms/Scalar/ConstraintElimination.cpp
+++ b/llvm/lib/Transforms/Scalar/ConstraintElimination.cpp
@@ -631,7 +631,6 @@ static Decomposition decompose(Value *V,
     Result.mul(CI->getSExtValue());
     return Result;
   }
-
   if (match(V, m_NUWSub(m_Value(Op0), m_Value(Op1)))) {
     auto ResA = decompose(Op0, Preconditions, IsSigned, DL);
     auto ResB = decompose(Op1, Preconditions, IsSigned, DL);
@@ -639,6 +638,25 @@ static Decomposition decompose(Value *V,
     return ResA;
   }

+  if (auto *II = dyn_cast<IntrinsicInst>(V)) {
+    switch (II->getIntrinsicID()) {
+    case Intrinsic::usub_sat:
+    case Intrinsic::ssub_sat: {
+      // usub.sat(X, C) = max(0, X - C) where C is a positive constant.
+      // This decomposes as X - C with a precondition that X >= C.
+      Value *X = II->getOperand(0);
+      Value *Y = II->getOperand(1);
+      auto ResA = decompose(X, Preconditions, IsSigned, DL);
+      auto ResB = decompose(Y, Preconditions, IsSigned, DL);
+      ResA.sub(ResB);
+      Preconditions.emplace_back(CmpInst::ICMP_UGE, X, Y);
+      return ResA;
+    }
+    default:
+      break;
+    }
+  }
+
   return {V, IsKnownNonNegative};
 }

